-- GENERATED by scripts/gen-seed.ts from src/lib/data/* — do not edit by hand.
-- Re-run: npm run db:gen-seed
-- Faithful snapshot of the in-repo mock data (today = 2026-06-20).

begin;

-- S3: `activity` is now a security_invoker VIEW over the append-only lot_event
-- ledger (not a table), so it is no longer truncatable/insertable directly. The
-- ledger is immutable (no DELETE), so the activity feed is re-seeded idempotently
-- via the _seed_activity_event() command RPC below (keyed per row → re-running this
-- seed file is a no-op for already-recorded events).
-- S4: daily_cherries / weekly_harvest / variety_shares / season_summary are no longer
-- tables — they were renamed aside to *_deprecated and the dashboard now reads
-- security_invoker VIEWS that COMPUTE these aggregates from `harvests`. So they're
-- dropped from this truncate + no longer seeded (seeding them would be dead data the
-- views ignore). The season HEADLINE inputs live in `farm_season_config` (seeded below).
-- cost_entry is added explicitly: it has NO FK to lots (target_code is un-FK'd by
-- design), so a `truncate lots cascade` does NOT reach it — without this, re-running
-- the seed re-inserts every cost and DOUBLES COGS (phase-1 review HIGH).
truncate table plots, workers, lots, harvests, processing_batches, tasks, weather, reserve_zones, cost_entry, crews, crew_memberships, worker_identity, worker_stream_event, attendance_event, por_obra_contracts, worker_certifications restart identity cascade;

