-- ── S8: EUDR traceability seed (plots of origin + deforestation-free claims) ──
-- The seeded green lots descend from milled sources JC-700/JC-710 that carried no
-- harvests, so they had no traceable origin. Tie real plots to those sources via
-- harvests (independent records — no conservation trigger): the green lot up-walk
-- then reaches them. JC-701 ← JC-700 ← {p-baru-vista, p-talamanca};
-- JC-711 ← JC-710 ← {p-nueva-suiza, p-palmira}. (Harvest weights are illustrative;
-- only the plot↔lot linkage matters to the dossier.)
-- EUDR origin-linkage harvests + early-season BULK harvest rows. All dated early in
-- the season (April) so they (a) establish each green lot's plots of origin for the
-- EUDR dossier and (b) make the dashboard SEASON HEADLINE coherent. The season view
-- sums cherries_kg from harvests (S4 "logged truth"), so with only the sparse recent
-- daily log the season ring read a broken ~3% of target (review finding). These bulk
-- rows bring the logged total in line with the farm's real scale (≈ the plots'
-- harvested_kg, ~122k) so the ring reads a realistic mid-late-season ~60%; the recent
-- daily log above still drives the today/daily/weekly trend (these April rows fall
-- outside that window). NOTE: a real full-season harvest log is generated by the
-- pipeline-UI slice; these bulk rows are the demo stand-in until then. (All target
-- non-green lots, so the harvests_no_green_target trigger permits them.)
insert into harvests (id, date, plot_id, worker_id, cherries_kg, ripeness_pct, brix_avg, lot_code) values
  ('h-eudr-700a', '2026-04-15', 'p-baru-vista',   'w-05',   320, 92, 22.4, 'JC-700'),
  ('h-eudr-700b', '2026-04-15', 'p-talamanca',    'w-03',   300, 90, 19.8, 'JC-700'),
  ('h-eudr-710a', '2026-04-15', 'p-nueva-suiza',  'w-14',   460, 89, 20.4, 'JC-710'),
  ('h-eudr-710b', '2026-04-15', 'p-palmira',      'w-13',   440, 87, 20.0, 'JC-710'),
  ('h-bulk-564',  '2026-04-10', 'p-tizingal-alto','w-06', 11800, 93, 22.5, 'JC-564'),
  ('h-bulk-541',  '2026-04-10', 'p-baru-vista',   'w-05',  6800, 92, 22.4, 'JC-541'),
  ('h-bulk-552',  '2026-04-10', 'p-talamanca',    'w-03', 22000, 90, 19.7, 'JC-552'),
  ('h-bulk-573',  '2026-04-10', 'p-nueva-suiza',  'w-14', 18800, 89, 20.3, 'JC-573'),
  ('h-bulk-588',  '2026-04-10', 'p-rio-sereno',   'w-13',  3600, 86, 21.2, 'JC-588'),
  ('h-bulk-596',  '2026-04-10', 'p-bambito',      'w-09', 13500, 88, 19.2, 'JC-596'),
  ('h-bulk-602',  '2026-04-10', 'p-las-lagunas',  'w-08', 16000, 96, 23.5, 'JC-602'),
  ('h-bulk-611',  '2026-04-10', 'p-palmira',      'w-14', 17500, 87, 20.1, 'JC-611');

-- Declare the deforestation-free status. JC-701's plots are fully declared
-- (basis: established before the 2020-12-31 cutoff, so no new clearing) → the lot
-- reads COMPLIANT. One of JC-711's plots (p-palmira) is left UNDECLARED so that
-- lot reads INCOMPLETE — the honest "cannot fully substantiate yet" demo state.
select eudr_declare_plot('p-baru-vista',  true, 'established-pre-cutoff');
select eudr_declare_plot('p-talamanca',   true, 'established-pre-cutoff');
select eudr_declare_plot('p-nueva-suiza', true, 'satellite-monitoring');
-- p-palmira intentionally left undeclared (demonstrates the INCOMPLETE verdict).

-- ── Advance the lot-code minter past every seeded code ───────────────────────
-- lot_code_seq starts at 700 but the seed hard-inserts JC-700/701/710/711 WITHOUT
-- advancing it, so the first real record_cherry_intake would mint 'JC-700' and
-- collide on lots_pkey (phase-1 review HIGH). Sync the sequence to the max seeded
-- JC number so the next mint is strictly greater. (The minter is also collision-
-- proof now — mig 20260621110000 — so this is belt-and-braces.)
select setval('lot_code_seq', (select max((split_part(code, '-', 2))::bigint)
                                 from lots where code ~ '^JC-[0-9]+$'));

-- ── P2-S7: payroll dogfood — a calculated pay period for the people-trunk capstone ──
-- The /payroll cockpit needs a real, frozen period to read. The make-whole guard,
-- statutory withholding, and the append-only ledgers all live in the migration; here
-- we seed the INPUTS (attendance hours + a tuned min wage) and run the live
-- compute_pay_period RPC so the dogfood shows a genuine snapshot — including ONE
-- worker the legal-minimum guard visibly lifts.
--
-- ⚠️ The min wage + statutory rates below are PLACEHOLDER demo values (DESIGN §4.1
-- Apply-OK gate). They make the make-whole + withholding render today; they are NOT
-- the confirmed Panama figures and must be set by the family/an accountant before a
-- real run. min_wage_hourly is tuned to 3.00/hr so a short-clocked picker falls under
-- the floor and the make-whole fires (with the 0.80 default, every full day clears it).
update farm_season_config
   set min_wage_hourly_usd = 3.00, standard_workday_hours = 8
 where id = 1;

-- A week of attendance for the picking crew (clock-in 13:00Z → clock-out 21:00Z = 8h),
-- written through the live record_attendance RPC so the hour-pairing the payroll view
-- relies on is exercised. w-06 (Lucía) gets a SHORT day (1h) so her blended pay falls
-- below the floor and the system tops her up — the dignity moment, made literal.
select record_attendance('w-03','clock-in',  null, '2026-06-16T13:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-att-w03-in');
select record_attendance('w-03','clock-out', null, '2026-06-16T21:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-att-w03-out');
select record_attendance('w-04','clock-in',  null, '2026-06-16T13:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-att-w04-in');
select record_attendance('w-04','clock-out', null, '2026-06-16T21:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-att-w04-out');
select record_attendance('w-08','clock-in',  null, '2026-06-17T13:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-att-w08-in');
select record_attendance('w-08','clock-out', null, '2026-06-17T21:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-att-w08-out');
-- Lucía: a short 1-hour clocked day → blended pay below the 3.00/hr floor → made whole.
select record_attendance('w-06','clock-in',  null, '2026-06-16T13:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-att-w06-in');
select record_attendance('w-06','clock-out', null, '2026-06-16T14:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-att-w06-out');

-- statutory rate row for the period (placeholder; supersedes the 2026-01-01 baseline).
insert into statutory_rates (effective_from, css_employee_pct, seguro_educativo_pct, decimo_accrual_pct, note)
values ('2026-06-01', 9.75, 1.25, 8.33, 'PLACEHOLDER demo rates — confirm with family/accountant before a real run.')
  on conflict (effective_from) do nothing;

-- Calculate (freeze the snapshot for) the demo week via the live command RPC.
select compute_pay_period('pp-2026-06-w3', '2026-06-15', '2026-06-21', '2026-2027', 'daily');

-- ── P2-S8: harvest-planning dogfood — real phenology + a pasada on the calendar ──
-- v_harvest_readiness LEFT-JOINs plot_phenology and coalesces a missing row to GDD 0,
-- so on a fresh seed with NO phenology every plot rendered ~0% / "No bloom logged" and
-- the pasada calendar was empty forever — the planner showed a wall of meaningless 0%
-- cards and the empty-states instructed the user to use controls that (until now) did
-- not exist. Log real maturation signals (a bloom + accumulated GDD, staggered down the
-- altitude gradient: the lower, warmer plots near their 2200 GDD requirement = ready;
-- the high Geisha early) through the LIVE record_maturation_signal RPC so the readiness
-- model derives genuine staggered scores, then schedule one pasada so the calendar is
-- non-empty and fires a real task onto the Tasks board. (Written via the command RPCs,
-- exercising the live write door — the seed never raw-inserts derived rows.)
select record_maturation_signal('p-cuesta-piedra','2026-01-10', 2120, 0.74, '2026-06-20T12:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-mat-cuesta');
select record_maturation_signal('p-palmira',      '2026-01-12', 2040, 0.71, '2026-06-20T12:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-mat-palmira');
select record_maturation_signal('p-talamanca',    '2026-01-20', 1760, 0.66, '2026-06-20T12:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-mat-talamanca');
select record_maturation_signal('p-nueva-suiza',  '2026-01-22', 1580, 0.62, '2026-06-20T12:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-mat-nuevasuiza');
select record_maturation_signal('p-bambito',      '2026-02-01', 1320, 0.58, '2026-06-20T12:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-mat-bambito');
select record_maturation_signal('p-tizingal-alto','2026-02-10',  980, 0.52, '2026-06-20T12:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-mat-tizingal');
select record_maturation_signal('p-las-lagunas',  '2026-02-12',  860, 0.49, '2026-06-20T12:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-mat-laslagunas');

-- Schedule the first pasada on the readiest plot (fires a Harvest task onto /tasks).
select schedule_pasada('p-cuesta-piedra', '2026', 1, '2026-06-28', 'high', '2026-06-20T12:00:00Z'::timestamptz, 'server', next_server_seq(), 'seed-pasada-cuesta');

